data.query:
mutation CreateMetafieldDefinition($definition: MetafieldDefinitionInput!) {
    metafieldDefinitionCreate(definition: $definition) {
        createdDefinition {
            id
            name
            namespace
            key
            ownerType
            type {
                name
            }
            description
            useAsCollectionCondition
        }
        userErrors {
            field
            message
            code
        }
    }
}
